// Apenas valida e monta parâmetros. A chamada HTTP ao snapshot vai no nó HTTP Request seguinte
// para evitar o timeout de 60s do task runner do Code node (N8N_RUNNERS_TASK_TIMEOUT).
const PANEL_BASE = 'https://longflatworm-n8n.cloudfy.live/webhook';
const input = $json || {};
const userId = String(input.user_id || '').trim();
const limit = Math.max(1, Math.min(500, +input.limit || 50));
const uf = input.uf ? String(input.uf).trim().toUpperCase() : '';
const seg = input.segmento ? String(input.segmento).trim().toLowerCase() : '';
const url = PANEL_BASE + '/castor-panel-snapshot' + (userId ? '?userId=' + encodeURIComponent(userId) : '');
return [{ json: { user_id: userId, limit, uf, seg, url, missing_user_id: !userId } }];

const params = $('Prepare params').first().json;
if (params.missing_user_id) {
  return [{ json: { ok: false, data: [], error: 'user_id_required' } }];
}
const resp = $json || {};
if (resp.error && !resp.ok) {
  // http-level error surfaced by continueOnFail
  return [{ json: { ok: false, data: [], error: 'snapshot_failed: ' + (resp.error.message || resp.error) } }];
}
if (!resp || resp.ok === false) {
  return [{ json: { ok: false, data: [], error: 'snapshot_failed: ' + ((resp && resp.error) || 'snapshot indisponivel') } }];
}
const snap = resp.data || {};
const limit = params.limit, uf = params.uf, seg = params.seg;
let rows = (snap.leads || []).slice();
if (uf) rows = rows.filter(l => (l.za7_est || '').toUpperCase() === uf);
if (seg) rows = rows.filter(l => (l.za7_segmento || '').toLowerCase().includes(seg));
rows.sort((a,b) => (a.za7_est||'').localeCompare(b.za7_est||'') || (a.za7_mun||'').localeCompare(b.za7_mun||'') || (a.za7_nome||'').localeCompare(b.za7_nome||''));
for (let i = 0; i < rows.length; i++) rows[i].fila_rank = i + 1;
const sliced = rows.slice(0, limit);
return [{ json: { ok: true, data: sliced, error: null, meta: { total: rows.length, returned: sliced.length, source: 'snapshot', generated_at: snap.generated_at } } }];
